{"tool": "execute_python", "args": {"code": "import json
import re
import os

# Read books data file
with open('books_info.json', 'r') as f:
    books_data = json.load(f)

print(f'Total books: {len(books_data)}')

# Extract publication years
def extract_year(details):
    years = re.findall(r'(\b19[0-9]{2}\b|\b20[0-2][0-9]\b|\b2023\b)', str(details))
    if years:
        return min([int(y) for y in years])
    return None

books = []
for book in books_data:
    year = extract_year(book.get('details', ''))
    if year:
        books.append({
            'book_id': book['book_id'],
            'year': year,
            'decade': (year // 10) * 10
        })

print(f'Books with years: {len(books)}')
print(f'Decades: {sorted(set(b["decade"] for b in books))}')

# Read reviews data
with open('reviews.json', 'r') as f:
    reviews = json.load(f)

print(f'Total reviews: {len(reviews)}')

# Map purchase_id to book_id numbers
book_ratings = {}
for review in reviews:
    purchase_id = review.get('purchase_id', '')
    rating = float(review.get('rating', 0))

    # Extract number from purchaseid_XXX
    match = re.search(r'(\d+)', purchase_id)
    if match:
        num = match.group(1)
        book_id = f'bookid_{num}'
        if book_id not in book_ratings:
            book_ratings[book_id] = []
        book_ratings[book_id].append(rating)

print(f'Unique books with reviews: {len(book_ratings)}')

# Calculate average rating by decade
decade_stats = {}
for decade in sorted(set(b['decade'] for b in books)):
    decade_books = [b for b in books if b['decade'] == decade and b['book_id'] in book_ratings]
    if len(decade_books) >= 10:
        ratings = []
        for book in decade_books:
            ratings.extend(book_ratings[book['book_id']])
        if ratings:
            avg_rating = sum(ratings) / len(ratings)
            decade_stats[decade] = {
                'num_books': len(decade_books),
                'avg_rating': avg_rating,
                'total_ratings': len(ratings)
            }

print(f'Decades with >=10 books: {len(decade_stats)}')
for decade, stats in sorted(decade_stats.items()):
    print(f'{decade}s: {stats["num_books"]} books, avg rating: {stats["avg_rating"]:.3f}')

if decade_stats:
    best_decade = max(decade_stats.items(), key=lambda x: x[1]['avg_rating'])
    print(f'\nBest decade: {best_decade[0]}s with avg rating {best_decade[1]["avg_rating"]:.3f}')

result = {'best_decade': best_decade[0] if decade_stats else None}
print('\n__RESULT__:')
print(json.dumps(result))"}, "id": "execute_python:35"} <|tool_call_end|> <|tool_calls_section_end|>

